class Solution:
    def minimumCost(self, nums: list, k: int, dist: int) -> int:
        # Brute force: try all ways to pick k-1 indices from [1, 1+dist]
        from itertools import combinations
        n = len(nums)
        best = float('inf')
        # i_1 in [1..n-1], i_{k-1} in [1..n-1], i_{k-1} - i_1 <= dist
        # choose k-1 indices from [1..n-1] with max-min <= dist
        pool = list(range(1, n))
        for combo in combinations(pool, k-1):
            if combo[-1] - combo[0] <= dist:
                best = min(best, nums[0] + sum(nums[i] for i in combo))
        return best

