var minimumCost = function(nums, k, dist) {
    // Use two sorted arrays as heaps (small/large) via manual sorted insert
    // For contest-grade JS we implement with two arrays kept sorted
    const need = k - 1;
    const n = nums.length;
    // Simple approach: sorted multiset simulation with arrays (ok for n<=1e5 with careful impl)
    // Use a different approach: just track sorted window with array for correctness
    // Actually implement with a balanced approach using sorted array slices:
    let small = [], large = [];
    let smallSum = 0;

    function bisect(arr, val) {
        let lo = 0, hi = arr.length;
        while (lo < hi) { const m = (lo+hi)>>1; if (arr[m] < val) lo = m+1; else hi = m; }
        return lo;
    }
    function insertSorted(arr, val) { arr.splice(bisect(arr, val), 0, val); }
    function removeSorted(arr, val) { const i = bisect(arr, val); if (arr[i] === val) arr.splice(i, 1); }

    function add(val) {
        if (small.length === need && small.length > 0 && val >= small[small.length-1]) {
            insertSorted(large, val);
        } else {
            insertSorted(small, val);
            smallSum += val;
            while (small.length > need) {
                const mv = small.pop();
                smallSum -= mv;
                insertSorted(large, mv);
            }
        }
    }
    function remove(val) {
        const idx = bisect(small, val);
        if (idx < small.length && small[idx] === val) {
            small.splice(idx, 1);
            smallSum -= val;
            if (large.length > 0 && small.length < need) {
                const mv = large.shift();
                insertSorted(small, mv);
                smallSum += mv;
            }
        } else {
            removeSorted(large, val);
        }
    }

    const winEnd = Math.min(1 + dist + 1, n);
    for (let i = 1; i < winEnd; i++) add(nums[i]);

    let best = nums[0] + smallSum;

    for (let i = 1 + dist + 1; i < n; i++) {
        add(nums[i]);
        remove(nums[i - dist - 1]);
        best = Math.min(best, nums[0] + smallSum);
    }

    return best;
};
